// ─── HELPERS ───────────────────────────────────────────────────────────────────
function useIsMobile() {
  const [m, setM] = useState(window.innerWidth < 640);
  useEffect(() => { const f = () => setM(window.innerWidth < 640); window.addEventListener("resize",f); return ()=>window.removeEventListener("resize",f); },[]);
  return m;
}
function getDaysInMonth(month, year) { return new Date(year, month+1, 0).getDate(); }
function getMonthStart(month, year) { const d = new Date(year,month,1).getDay(); return d===0?6:d-1; }

// Para cuantificables: dayData es un número directo (la opción elegida)
function getDayDone(dayData, habit) {
  if (!habit.quantifiable) return !!dayData;
  const val = Number(dayData);
  return !isNaN(val) && val > 0;
}
function getDayValue(dayData, habit) {
  if (!habit.quantifiable) return dayData ? 1 : 0;
  return Number(dayData) || 0;
}

function getMonthProgress(habit, month) {
  const days = habit.monthData[month]?.days || [];
  const past = days.filter((_,i) => !(month===CURRENT_MONTH && i>=TODAY_DAY));
  const done = past.filter(d => getDayDone(d, habit));
  return past.length ? Math.round((done.length/past.length)*100) : 0;
}

function getWeeklyProgress(habit, month) {
  const days = habit.monthData[month]?.days || [];
  const freq = habit.freqPerWeek;
  const weeks = Math.ceil(days.length/7);
  let met=0, total=0;
  for (let w=0; w<weeks; w++) {
    const slice = days.slice(w*7,(w+1)*7);
    const pastCount = slice.filter((_,i)=>!(month===CURRENT_MONTH&&w*7+i>=TODAY_DAY)).length;
    const doneCount = slice.filter((d,i)=>!(month===CURRENT_MONTH&&w*7+i>=TODAY_DAY)&&getDayValue(d,habit)>0).length;
    if (pastCount>0) { total++; if (doneCount>=freq) met++; }
  }
  return {met, total};
}

function getVarAverage(habit, month) {
  if (!habit.quantifiable) return null;
  const days = habit.monthData[month]?.days || [];
  const vals = days.filter((_,i)=>!(month===CURRENT_MONTH&&i>=TODAY_DAY)).map(d=>Number(d)||0).filter(v=>v>0);
  if (!vals.length) return "—";
  const avg = vals.reduce((a,b)=>a+b,0)/vals.length;
  // Encontrar la opción cuyo valor es más cercano al promedio y devolver su etiqueta
  if (habit.varOptions && habit.varOptions.length>0) {
    const closest = habit.varOptions.reduce((prev,curr)=>
      Math.abs(curr.value-avg) < Math.abs(prev.value-avg) ? curr : prev
    );
    return closest.label;
  }
  return avg.toFixed(1);
}

function initMonthData(n) { return { days: Array(n).fill(null) }; }

function buildHabit(h, idx) {
  const monthData = {};
  MONTHS.forEach((_,mi) => { monthData[mi] = initMonthData(getDaysInMonth(mi, CURRENT_YEAR)); });
  return {
    ...h,
    id: h.id || Date.now()+idx,
    colorIdx: idx % CATEGORY_COLORS.length,
    monthData,
    freqPerWeek: h.freqPerWeek||7,
    streak: h.streak||0,
    completedToday: false,
    // quantifiable fields
    varName: h.varName||"",         // nombre de la variable, ej "botilitos"
    varOptions: h.varOptions||[],   // opciones: [{label:"1 botilito", value:1}, ...]
  };
}

// ─── MINI CALENDAR ─────────────────────────────────────────────────────────────
function MiniCalendar({ habit, month, color, onToggle, interactive }) {
  const year = CURRENT_YEAR;
  const daysInM = getDaysInMonth(month, year);
  const startOffset = getMonthStart(month, year);
  const totalCells = Math.ceil((daysInM+startOffset)/7)*7;
  const days = habit.monthData[month]?.days||[];

  return (
    <div style={{width:"100%"}}>
      <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:"2px",marginBottom:"4px"}}>
        {WEEK_DAYS.map(d=><div key={d} style={{textAlign:"center",fontSize:"9px",color:"#9CA3AF",fontWeight:600}}>{d}</div>)}
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:"3px"}}>
        {Array.from({length:totalCells},(_,i)=>{
          const di = i-startOffset;
          if (di<0||di>=daysInM) return <div key={i} style={{aspectRatio:"1"}}/>;
          const isFuture = month===CURRENT_MONTH && di>=TODAY_DAY;
          const isToday = month===CURRENT_MONTH && di===TODAY_DAY-1;
          const done = getDayDone(days[di], habit);
          return (
            <div key={i} onClick={()=>interactive&&!isFuture&&onToggle&&onToggle(di)}
              title={`Día ${di+1}${habit.quantifiable&&days[di]?' · '+days[di]+' '+habit.varName:''}`}
              style={{width:"100%",aspectRatio:"1",borderRadius:"50%",
                backgroundColor:isFuture?"#F3F4F6":done?color:"#E5E7EB",
                opacity:isFuture?0.3:1,
                cursor:interactive&&!isFuture?"pointer":"default",
                border:isToday?`2px solid ${color}`:"none",
                boxSizing:"border-box",
              }}
            />
          );
        })}
      </div>
    </div>
  );
}

// ─── DOT BAR ───────────────────────────────────────────────────────────────────
function DotBar({progress, color, size=10}) {
  const bars = Math.round(progress/10);
  return (
    <div style={{display:"flex",gap:"3px",alignItems:"center"}}>
      {Array.from({length:10},(_,i)=>(
        <div key={i} style={{width:size,height:size,borderRadius:"50%",flexShrink:0,background:i<bars?color:"#E5E7EB"}}/>
      ))}
      <span style={{marginLeft:"6px",fontSize:"11px",color:"#9CA3AF",fontWeight:600,whiteSpace:"nowrap"}}>{progress}%</span>
    </div>
  );
}

